const items = $input.all();
const fetchDate = new Date().toISOString();

function cleanText(text) {
  if (!text) return '';
  return text
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/gi, '$1')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&#8217;/gi, "'")
    .replace(/&#8216;/gi, "'")
    .replace(/&#8220;/gi, '"')
    .replace(/&#8221;/gi, '"')
    .replace(/&#8211;/gi, "-")
    .replace(/&#8212;/gi, "--")
    .replace(/&#8230;/gi, "...")
    .replace(/&#[0-9]+;/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractXmlTag(xml, tag) {
  if (!xml) return '';
  const cdataRegex = new RegExp('<' + tag + '[^>]*>\\s*<!\\[CDATA\\[([\\s\\S]*?)\\]\\]>\\s*</' + tag + '>', 'i');
  let match = xml.match(cdataRegex);
  if (match) return cleanText(match[1]);
  const plainRegex = new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)</' + tag + '>', 'i');
  match = xml.match(plainRegex);
  if (match) return cleanText(match[1]);
  return '';
}

function extractLink(itemXml) {
  let link = extractXmlTag(itemXml, 'feedburner:origLink') || extractXmlTag(itemXml, 'link');
  if (!link || !link.startsWith('http')) {
    const hrefMatch = itemXml.match(/<link[^>]+href=["']([^"']+)["']/i);
    if (hrefMatch) link = hrefMatch[1];
  }
  if (!link || !link.startsWith('http')) {
    const guid = extractXmlTag(itemXml, 'guid');
    if (guid && guid.startsWith('http')) link = guid;
  }
  return link ? link.trim() : '';
}

function extractPubDate(itemXml) {
  return extractXmlTag(itemXml, 'pubDate') || extractXmlTag(itemXml, 'dc:date') || extractXmlTag(itemXml, 'published') || extractXmlTag(itemXml, 'updated');
}

function extractDescription(itemXml) {
  const desc = extractXmlTag(itemXml, 'description') || extractXmlTag(itemXml, 'content:encoded') || extractXmlTag(itemXml, 'summary') || extractXmlTag(itemXml, 'content');
  return cleanText(desc);
}

function extractItemsFromXml(xmlText, sourceName) {
  if (!xmlText || typeof xmlText !== 'string') return [];
  let itemMatches = xmlText.match(/<item[\s>][\s\S]*?<\/item>/gi);
  if (!itemMatches || itemMatches.length === 0) {
    itemMatches = xmlText.match(/<entry[\s>][\s\S]*?<\/entry>/gi) || [];
  }
  return itemMatches.map(itemXml => {
    const title = extractXmlTag(itemXml, 'title');
    const link = extractLink(itemXml);
    const pubDate = extractPubDate(itemXml);
    const description = extractDescription(itemXml);
    const author = extractXmlTag(itemXml, 'dc:creator') || extractXmlTag(itemXml, 'author') || extractXmlTag(itemXml, 'name');
    const categoryMatches = itemXml.match(/<category[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/category>/gi) || [];
    const categories = categoryMatches.map(c => {
      const m = c.match(/<category[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/category>/i);
      return m ? cleanText(m[1]) : '';
    }).filter(Boolean).slice(0, 5);
    let timestamp = 0;
    if (pubDate) {
      const parsed = Date.parse(pubDate);
      if (!isNaN(parsed)) timestamp = parsed;
    }
    const truncatedDesc = description.length > 300 ? description.substring(0, 300) + '...' : description;
    return {
      title: title,
      link: link,
      pubDate: pubDate,
      timestamp: timestamp,
      description: truncatedDesc,
      author: author,
      categories: categories,
      source: sourceName
    };
  });
}

const allArticles = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let xmlText = '';
  if (typeof item.json.data === 'string') {
    xmlText = item.json.data;
  } else if (typeof item.json.body === 'string') {
    xmlText = item.json.body;
  } else if (typeof item.json === 'string') {
    xmlText = item.json;
  } else if (item.json && typeof item.json === 'object') {
    xmlText = JSON.stringify(item.json);
  }
  const xmlLower = xmlText.toLowerCase();
  let sourceName = 'Unknown Source';
  if (xmlLower.includes('venturebeat')) {
    sourceName = 'VentureBeat';
  } else if (xmlLower.includes('techcrunch')) {
    sourceName = 'TechCrunch';
  } else {
    sourceName = i === 0 ? 'VentureBeat' : 'TechCrunch';
  }
  const parsed = extractItemsFromXml(xmlText, sourceName);
  allArticles.push(...parsed);
}

const sevenDaysAgo = Date.now() - (7 * 24 * 60 * 60 * 1000);
const filtered = allArticles
  .filter(a => a.title && a.link && a.timestamp >= sevenDaysAgo)
  .sort((a, b) => b.timestamp - a.timestamp)
  .slice(0, 25);

const seenTitles = new Set();
const deduplicated = filtered.filter(a => {
  const normalized = a.title.toLowerCase().trim();
  if (seenTitles.has(normalized)) return false;
  seenTitles.add(normalized);
  return true;
});

return [{
  json: {
    articles: deduplicated,
    articleCount: deduplicated.length,
    fetchDate: fetchDate,
    sources: ['VentureBeat AI', 'TechCrunch AI'],
    dateRange: {
      from: new Date(sevenDaysAgo).toISOString(),
      to: fetchDate
    }
  }
}];

const aiOutput = $json.output || '';
const parseData = $('Parse & Filter Articles').first()?.json || {};
const articleCount = parseData.articleCount ?? $json.articleCount ?? 0;
const fetchDate = parseData.fetchDate || $json.fetchDate || new Date().toISOString();
const dateStr = new Date(fetchDate).toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

function markdownToHtml(md) {
  if (!md) return '';
  const lines = md.replace(/\r\n/g, '\n').split('\n');
  const htmlLines = [];
  let inList = false;

  for (let i = 0; i < lines.length; i++) {
    let line = lines[i];
    let trimmed = line.trim();

    if (trimmed === '') {
      if (inList) {
        htmlLines.push('</ul>');
        inList = false;
      }
      continue;
    }

    if (trimmed.startsWith('## ')) {
      if (inList) {
        htmlLines.push('</ul>');
        inList = false;
      }
      const headerText = trimmed.replace(/^##\s+/, '');
      const formattedHeader = headerText
        .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" class="link-text" style="color: #2563eb; text-decoration: underline;">$1</a>');
      htmlLines.push('<h2 class="heading-text" style="color: #1e293b; font-size: 18px; margin-top: 24px; margin-bottom: 12px; border-bottom: 1px solid #e2e8f0; padding-bottom: 6px; font-weight: 600;">' + formattedHeader + '</h2>');
      continue;
    }

    if (trimmed.startsWith('# ')) {
      if (inList) {
        htmlLines.push('</ul>');
        inList = false;
      }
      const headerText = trimmed.replace(/^#\s+/, '');
      const formattedHeader = headerText
        .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" class="link-text" style="color: #2563eb; text-decoration: underline;">$1</a>');
      htmlLines.push('<h1 class="heading-text" style="color: #0f172a; font-size: 22px; margin-top: 24px; margin-bottom: 12px; font-weight: 700;">' + formattedHeader + '</h1>');
      continue;
    }

    if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
      const itemContent = trimmed.substring(2);
      const formattedItem = itemContent
        .replace(/\*\*([^*]+)\*\*/g, '<strong class="text-primary" style="color: #0f172a;">$1</strong>')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" class="link-text" style="color: #2563eb; text-decoration: underline; font-weight: 500;">$1</a>');

      if (!inList) {
        htmlLines.push('<ul class="text-secondary" style="margin: 12px 0; padding-left: 20px; color: #334155;">');
        inList = true;
      }
      htmlLines.push('<li style="margin-bottom: 8px; line-height: 1.6;">' + formattedItem + '</li>');
      continue;
    }

    if (inList && (line.startsWith('  ') || line.startsWith('\t'))) {
      const continuationText = trimmed
        .replace(/\*\*([^*]+)\*\*/g, '<strong class="text-primary" style="color: #0f172a;">$1</strong>')
        .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" class="link-text" style="color: #2563eb; text-decoration: underline; font-weight: 500;">$1</a>');

      const lastIdx = htmlLines.length - 1;
      if (lastIdx >= 0 && htmlLines[lastIdx].endsWith('</li>')) {
        htmlLines[lastIdx] = htmlLines[lastIdx].slice(0, -5) + '<br>' + continuationText + '</li>';
      } else {
        htmlLines.push(continuationText);
      }
      continue;
    }

    if (inList) {
      htmlLines.push('</ul>');
      inList = false;
    }

    const formattedParagraph = trimmed
      .replace(/\*\*([^*]+)\*\*/g, '<strong class="text-primary" style="color: #0f172a;">$1</strong>')
      .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" class="link-text" style="color: #2563eb; text-decoration: underline; font-weight: 500;">$1</a>');

    htmlLines.push('<p class="text-secondary" style="margin: 0 0 12px 0; color: #334155; line-height: 1.6; font-size: 15px;">' + formattedParagraph + '</p>');
  }

  if (inList) {
    htmlLines.push('</ul>');
  }

  return htmlLines.join('\n');
}

const htmlContent = markdownToHtml(aiOutput);

const emailHtml = '<!DOCTYPE html>'
