  + '  .header-bg { background-color: #0f172a !important; background-image: linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #312e81 100%) !important; }'
  + '  .header-title, .header-title span { color: #ffffff !important; -webkit-text-fill-color: #ffffff !important; }'
  + '  .header-date, .header-date span { color: #cbd5e1 !important; -webkit-text-fill-color: #cbd5e1 !important; }'
  + '  .text-primary { color: #f8fafc !important; }'
  + '  .text-secondary { color: #cbd5e1 !important; }'
  + '  .text-muted { color: #94a3b8 !important; }'
  + '  .heading-text { color: #38bdf8 !important; border-color: #334155 !important; }'
  + '  .link-text { color: #60a5fa !important; }'
  + '  .divider { border-color: #334155 !important; }'
  + '}'
  + '</style>'
  + '</head>'
  + '<body class="email-body" style="margin: 0; padding: 20px 10px; background-color: #f8fafc; font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, Helvetica, Arial, sans-serif;">'
  + '<table role="presentation" width="100%" border="0" cellspacing="0" cellpadding="0">'
  + '<tr><td align="center">'
  + '<table role="presentation" width="100%" border="0" cellspacing="0" cellpadding="0" style="max-width: 680px; margin: 0 auto;">'
  + '<tr>'
  + '<td class="header-bg" style="background-color: #1e1b4b; background-image: linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #312e81 100%); padding: 32px; border-radius: 12px 12px 0 0; text-align: left;">'
  + '<h1 class="header-title" style="margin: 0 0 8px 0; font-size: 24px; font-weight: 700; color: #ffffff !important; line-height: 1.3;">'
  + '<span style="color: #ffffff !important;">AI &amp; Automation Weekly Digest</span>'
  + '</h1>'
  + '<p class="header-date" style="margin: 0; font-size: 14px; color: #e2e8f0 !important; opacity: 0.95;">'
  + '<span style="color: #e2e8f0 !important;">' + dateStr + '</span>'
  + '</p>'
  + '</td>'
  + '</tr>'
  + '<tr>'
  + '<td class="card-bg" style="background-color: #ffffff; padding: 32px; border: 1px solid #e2e8f0; border-top: none; border-radius: 0 0 12px 12px;">'
  + '<div class="text-muted divider" style="font-size: 13px; color: #64748b; margin-bottom: 24px; padding-bottom: 16px; border-bottom: 1px solid #f1f5f9;">'
  + '<strong class="text-primary" style="color: #0f172a;">' + articleCount + ' articles</strong> analyzed from VentureBeat AI &amp; TechCrunch AI'
  + '</div>'
  + '<div>' + htmlContent + '</div>'
  + '<div class="text-muted divider" style="margin-top: 32px; padding-top: 16px; border-top: 1px solid #f1f5f9; font-size: 12px; color: #94a3b8; text-align: center;">'
  + '<p style="margin: 0;">Generated automatically by AI-Powered Competitor Monitor</p>'
  + '<p style="margin: 4px 0 0 0;">Powered by n8n + Google Gemini</p>'
  + '</div>'
  + '</td>'
  + '</tr>'
  + '</table>'
  + '</td>'
  + '</tr>'
  + '</table>'
  + '</body>'
  + '</html>';

const plainText = 'AI & AUTOMATION WEEKLY DIGEST\n' + dateStr + '\n' + articleCount + ' articles analyzed\n\n' + aiOutput + '\n\n---\nGenerated by AI-Powered Competitor Monitor | Powered by n8n + Google Gemini';

const markdownText = '# AI & Automation Weekly Digest\n*' + dateStr + '* | *' + articleCount + ' articles analyzed*\n\n' + aiOutput + '\n\n---\n*Sources: VentureBeat AI & TechCrunch AI | Generated by n8n + Google Gemini*';

return [{
  json: {
    formattedText: markdownText,
    formattedHtml: emailHtml,
    plainText: plainText,
    subject: 'AI Weekly Digest - ' + dateStr + ' (' + articleCount + ' articles)',
    meta: { generatedAt: new Date().toISOString(), articleCount: articleCount }
  }
}];
